@dataclass
class ReconciliationLine:
    account_id: str
    currency: str
    internal_balance: Decimal
    external_balance: Decimal
    variance: Decimal
    as_of_date: date

    @property
    def is_reconciled(self) -> bool:
        return self.variance == Decimal("0")


@dataclass
class ReconciliationReport:
    report_id: str
    report_date: date
    generated_at: datetime
    lines: list[ReconciliationLine] = field(default_factory=list)
    incidents_opened: list[str] = field(default_factory=list)

    @property
    def total_variance(self) -> Decimal:
        return sum(line.variance for line in self.lines)

    @property
    def has_variances(self) -> bool:
        return any(not line.is_reconciled for line in self.lines)

    @property
    def unreconciled_lines(self) -> list[ReconciliationLine]:
        return [line for line in self.lines if not line.is_reconciled]


